import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitize and escape user input to prevent XSS
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Write sanitized user input to a secure HTML file
        File outputFile = new File("output.html");
        FileWriter writer = new FileWriter(outputFile);

        writer.write("<html><head><title>XSS Prevention</title></head><body>");
        writer.write("<h1>Welcome, " + sanitizedUserInput + "</h1>");
        writer.write("</body></html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
